import csv, io, json, math, os, statistics, urllib.request, zipfile, xml.etree.ElementTree as ET
from datetime import datetime, timezone
from pathlib import Path

OUT=Path('dist'); OUT.mkdir(exist_ok=True)
FEED='https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/2.5_week.geojson'
PLATE_CANDIDATES=[
 'https://earthquake.usgs.gov/learn/plate-boundaries.kmz',
 'https://earthquake.usgs.gov/static/lfs/learn/plate-boundaries.kmz',
 'https://earthquake.usgs.gov/learn/kml/plate-boundaries.kmz'
]

def get(url):
 req=urllib.request.Request(url,headers={'User-Agent':'RestlessPlanet/1.0 scientific visualization'})
 with urllib.request.urlopen(req,timeout=60) as r:return r.read()

retrieved=datetime.now(timezone.utc).isoformat().replace('+00:00','Z')
raw=get(FEED); feed=json.loads(raw)
byid={f['id']:f for f in feed['features']}; features=list(byid.values())
if not features: raise RuntimeError('USGS feed returned no events')
for f in features:
 lon,lat,depth=f['geometry']['coordinates']
 if not (-180<=lon<=180 and -90<=lat<=90): raise ValueError(f'Invalid coordinates {f["id"]}')

plate_raw=None; plate_url=None
for u in PLATE_CANDIDATES:
 try:
  plate_raw=get(u); plate_url=u; break
 except Exception: pass
if plate_raw is None: raise RuntimeError('Official USGS plate-boundary KMZ could not be retrieved from known USGS endpoints')

# Parse KML/KMZ coordinates. Preserve source geometry; no inferred boundary classification.
if plate_raw[:2]==b'PK':
 z=zipfile.ZipFile(io.BytesIO(plate_raw)); kml=z.read(next(n for n in z.namelist() if n.lower().endswith('.kml')))
else:kml=plate_raw
root=ET.fromstring(kml)
segments=[]
for el in root.iter():
 if el.tag.endswith('coordinates') and el.text:
  pts=[]
  for tok in el.text.replace('\n',' ').split():
   p=tok.split(',')
   if len(p)>=2:
    try: pts.append([float(p[0]),float(p[1])])
    except: pass
  if len(pts)>1: segments.append(pts)
if not segments: raise RuntimeError('USGS plate-boundary file contained no parseable line geometry')

# Frozen source files
(OUT/'earthquakes.geojson').write_bytes(raw)
(OUT/'plate-boundaries.kmz').write_bytes(plate_raw)

fields=['event_id','latitude','longitude','depth_km','magnitude','magnitude_type','place','origin_time_utc','updated_time_utc','review_status','tsunami_flag','event_url']
rows=[]
for f in sorted(features,key=lambda x:x['properties']['time']):
 p=f['properties']; lon,lat,dep=f['geometry']['coordinates']
 rows.append({'event_id':f['id'],'latitude':lat,'longitude':lon,'depth_km':dep,'magnitude':p.get('mag'),'magnitude_type':p.get('magType'),'place':p.get('place'),'origin_time_utc':datetime.fromtimestamp(p['time']/1000,timezone.utc).isoformat().replace('+00:00','Z'),'updated_time_utc':datetime.fromtimestamp(p['updated']/1000,timezone.utc).isoformat().replace('+00:00','Z'),'review_status':p.get('status'),'tsunami_flag':p.get('tsunami'),'event_url':p.get('url')})
with open(OUT/'earthquakes.csv','w',newline='',encoding='utf-8') as fh:
 w=csv.DictWriter(fh,fieldnames=fields);w.writeheader();w.writerows(rows)

compact=[]
for f in features:
 p=f['properties']; lon,lat,dep=f['geometry']['coordinates']
 compact.append({'id':f['id'],'lat':lat,'lon':lon,'depth':dep,'mag':p.get('mag'),'magType':p.get('magType'),'place':p.get('place'),'time':p.get('time'),'updated':p.get('updated'),'status':p.get('status'),'tsunami':p.get('tsunami'),'url':p.get('url')})
compact.sort(key=lambda x:x['time'])
start=min(x['time'] for x in compact); end=max(x['time'] for x in compact)
validm=[x['mag'] for x in compact if x['mag'] is not None]; validd=[x['depth'] for x in compact if x['depth'] is not None]
top5=sorted(compact,key=lambda x:(x['mag'] is not None,x['mag'] or -999),reverse=True)[:5]
meta={'retrieved':retrieved,'feed_generated':datetime.fromtimestamp(feed['metadata']['generated']/1000,timezone.utc).isoformat().replace('+00:00','Z'),'count':len(compact),'start':start,'end':end,'minMag':min(validm),'maxMag':max(validm),'minDepth':min(validd),'maxDepth':max(validd),'feed':FEED,'plate':plate_url,'top5':[x['id'] for x in top5]}

